1000	// populateWorkerStatus fills in the Status and Detail fields on a worker result
1001	// based on the task-level Outcome.
1002	func populateWorkerStatus(res *ExecuteBeadResult) {
1003		switch res.Outcome {
1004		case ExecuteBeadOutcomeTaskSucceeded:
1005			res.Status = ExecuteBeadStatusSuccess
1006		case ExecuteBeadOutcomeTaskNoChanges:
1007			res.Status = ExecuteBeadStatusNoChanges
1008		case ExecuteBeadOutcomeTaskNoEvidence:
1009			res.Status = ExecuteBeadStatusNoEvidenceProduced
1010		default:
1011			res.Status = ExecuteBeadStatusExecutionFailed
1012		}
1013		res.Detail = ExecuteBeadStatusDetail(res.Status, "", res.Error)
1014	}
