1016	// CommitTracker commits beads.jsonl if it has uncommitted changes.
1017	func CommitTracker(projectRoot string) error {
1018		trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
1019		info, err := os.Stat(trackerFile)
1020		if err != nil {
1021			if os.IsNotExist(err) {
1022				return nil
1023			}
1024			return fmt.Errorf("checking tracker file: %w", err)
1025		}
1026		if info.IsDir() {
1027			return nil
1028		}
1029	
1030		out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
1031		if err != nil || strings.TrimSpace(string(out)) != "true" {
1032			return nil
1033		}
1034	
1035		msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
1036		// Serialize git add/commit on the primary .git across processes so that
1037		// concurrent workers (multiple `ddx work --local`) do not race on
1038		// .git/index.lock. See cli/internal/agent/tracker_lock.go.
1039		return withTrackerLock(projectRoot, func() error {
1040			// Re-check inside the lock: a sibling worker may have already
1041			// committed the tracker changes between our pre-lock check and now.
1042			diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
1043			if err != nil {
1044				return fmt.Errorf("checking tracker diff: %w", err)
1045			}
1046			if strings.TrimSpace(string(diff)) == "" {
1047				untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
1048				if err != nil {
1049					return fmt.Errorf("checking tracker untracked: %w", err)
1050				}
1051				if strings.TrimSpace(string(untracked)) == "" {
1052					return nil
1053				}
1054			}
1055	
1056			commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
1057			if err != nil {
1058				return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1059			}
1060			// `git commit` would fail with "nothing to commit" if the file's
1061			// content is byte-identical to HEAD even though `git diff` saw a
1062			// diff (e.g. mode/whitespace race). Bail cleanly in that case.
1063			if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
1064				return nil
1065			}
1066			commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "-m", msg).CombinedOutput()
1067			if err != nil {
1068				return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1069			}
1070			return nil
1071		})
1072	}
