1074	func resolveBase(gitOps GitOps, workDir, fromRev string) (string, error) {
1075		if fromRev == "" || fromRev == "HEAD" {
1076			rev, err := gitOps.HeadRev(workDir)
1077			if err != nil {
1078				return "", fmt.Errorf("resolving HEAD: %w", err)
1079			}
1080			return rev, nil
1081		}
1082		rev, err := gitOps.ResolveRev(workDir, fromRev)
1083		if err != nil {
1084			return "", fmt.Errorf("resolving --from %q: %w", fromRev, err)
1085		}
1086		return rev, nil
1087	}
